#!/usr/bin/env python3
"""
Script to apply NoScheduleNoTraffic taint effect changes to Kubernetes codebase.
Run this script with elevated privileges to apply all necessary modifications.
"""

import os
import sys
import re

def apply_changes():
    """Apply all NoScheduleNoTraffic changes to the Kubernetes codebase."""

    changes_made = []
    errors = []

    # Change 1: staging/src/k8s.io/api/core/v1/types.go
    types_file_path = "/workspace/staging/src/k8s.io/api/core/v1/types.go"
    print(f"Processing {types_file_path}...")

    try:
        with open(types_file_path, 'r') as f:
            types_content = f.read()

        # Add TaintEffectNoScheduleNoTraffic constant
        old_const = '''	// Evict any already-running pods that do not tolerate the taint.
	// Currently enforced by NodeController.
	TaintEffectNoExecute TaintEffect = "NoExecute"
)'''

        new_const = '''	// Evict any already-running pods that do not tolerate the taint.
	// Currently enforced by NodeController.
	TaintEffectNoExecute TaintEffect = "NoExecute"
	// Do not allow new pods to schedule onto the node unless they tolerate the taint,
	// and remove the node from service endpoints. Does not evict existing pods.
	// Enforced by the scheduler and the EndpointSlice controller.
	TaintEffectNoScheduleNoTraffic TaintEffect = "NoScheduleNoTraffic"
)'''

        if old_const in types_content:
            types_content = types_content.replace(old_const, new_const)
            changes_made.append("Added TaintEffectNoScheduleNoTraffic constant")
        else:
            errors.append(f"Could not find constant definition in {types_file_path}")

        # Update toleration documentation
        old_doc = "// When specified, allowed values are NoSchedule, PreferNoSchedule and NoExecute."
        new_doc = "// When specified, allowed values are NoSchedule, PreferNoSchedule, NoExecute and NoScheduleNoTraffic."

        if old_doc in types_content:
            types_content = types_content.replace(old_doc, new_doc)
            changes_made.append("Updated Toleration Effect documentation")
        else:
            errors.append(f"Could not find toleration documentation in {types_file_path}")

        # Write the modified content
        with open(types_file_path, 'w') as f:
            f.write(types_content)

    except Exception as e:
        errors.append(f"Error processing {types_file_path}: {e}")

    # Change 2: pkg/scheduler/framework/plugins/helper/taint.go
    taint_helper_path = "/workspace/pkg/scheduler/framework/plugins/helper/taint.go"
    print(f"Processing {taint_helper_path}...")

    try:
        with open(taint_helper_path, 'r') as f:
            helper_content = f.read()

        old_filter = '''	return func(t *v1.Taint) bool {
		// PodToleratesNodeTaints is only interested in NoSchedule and NoExecute taints.
		return t.Effect == v1.TaintEffectNoSchedule || t.Effect == v1.TaintEffectNoExecute
	}'''

        new_filter = '''	return func(t *v1.Taint) bool {
		// PodToleratesNodeTaints is only interested in NoSchedule, NoExecute and NoScheduleNoTraffic taints.
		return t.Effect == v1.TaintEffectNoSchedule || t.Effect == v1.TaintEffectNoExecute || t.Effect == v1.TaintEffectNoScheduleNoTraffic
	}'''

        if old_filter in helper_content:
            helper_content = helper_content.replace(old_filter, new_filter)
            changes_made.append("Updated DoNotScheduleTaintsFilterFunc")

            with open(taint_helper_path, 'w') as f:
                f.write(helper_content)
        else:
            errors.append(f"Could not find filter function in {taint_helper_path}")

    except Exception as e:
        errors.append(f"Error processing {taint_helper_path}: {e}")

    # Change 3: staging/src/k8s.io/endpointslice/utils.go
    utils_path = "/workspace/staging/src/k8s.io/endpointslice/utils.go"
    print(f"Processing {utils_path}...")

    try:
        with open(utils_path, 'r') as f:
            utils_content = f.read()

        # Add NoScheduleNoTraffic check in podToEndpoint function
        old_func_start = '''// podToEndpoint returns an Endpoint object generated from a Pod, a Node, and a Service for a particular addressType.
func podToEndpoint(pod *v1.Pod, node *v1.Node, service *v1.Service, addressType discovery.AddressType) discovery.Endpoint {'''

        new_func_start = '''// podToEndpoint returns an Endpoint object generated from a Pod, a Node, and a Service for a particular addressType.
// If the node has a NoScheduleNoTraffic taint, this function will return an endpoint with no addresses.
func podToEndpoint(pod *v1.Pod, node *v1.Node, service *v1.Service, addressType discovery.AddressType) discovery.Endpoint {
	// Check if the node has a NoScheduleNoTraffic taint
	if node != nil {
		for _, taint := range node.Spec.Taints {
			if taint.Effect == v1.TaintEffectNoScheduleNoTraffic {
				// Return endpoint without addresses if node has NoScheduleNoTraffic taint
				return discovery.Endpoint{
					Addresses: []string{},
					Conditions: discovery.EndpointConditions{
						Ready:       nil,
						Serving:     nil,
						Terminating: nil,
					},
					TargetRef: &v1.ObjectReference{
						Kind:      "Pod",
						Namespace: pod.ObjectMeta.Namespace,
						Name:      pod.ObjectMeta.Name,
						UID:       pod.ObjectMeta.UID,
					},
				}
			}
		}
	}'''

        if old_func_start in utils_content:
            utils_content = utils_content.replace(old_func_start, new_func_start)
            changes_made.append("Updated podToEndpoint function to filter NoScheduleNoTraffic nodes")

            with open(utils_path, 'w') as f:
                f.write(utils_content)
        else:
            errors.append(f"Could not find podToEndpoint function in {utils_path}")

    except Exception as e:
        errors.append(f"Error processing {utils_path}: {e}")

    # Print results
    print("\n=== Changes Applied ===")
    for change in changes_made:
        print(f"✓ {change}")

    if errors:
        print("\n=== Errors ===")
        for error in errors:
            print(f"✗ {error}")
        return 1

    print("\n✓ All changes applied successfully!")
    return 0

if __name__ == "__main__":
    sys.exit(apply_changes())

